VALUES
  ('pukao-7ec62a85-moex-00082', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於行政契約與行政處分之敘述，下列何者錯誤？', '["兩者同屬行政機關對個別事件所為具有對外效力之行政行為", "行政契約之一部無效者，原則上其他部分仍為有效；行政處分一部分無效者，原則上全部無效", "除法令有特別規定者外，行政機關作成行政處分有形式選擇自由時，得締結行政契約以替代行政處分", "行政契約之締結，原則上應以書面為之；行政處分原則上得以書面、言詞或其他方式為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00083', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於行政法上觀念通知之敘述，下列何者正確？', '["不發生規制之法律效果", "屬於私經濟行政行為", "不受法規支配之行政行為", "其爭議由民事法院審理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00084', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列何種行政行為屬於行政罰？', '["因受益人未履行負擔，主管機關廢止原先核發之營業許可", "因受益人提供錯誤資訊，主管機關撤銷先前作成之建築許可", "稅捐稽徵機關為保全稅捐，限制欠稅人民出境", "事業經營者因違反營業法規，遭主管機關勒令停業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00085', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於行政罰法規定之敘述，下列何者正確？', '["我國行政罰法採取法定原則，對所有違反行政法義務者皆予以處罰", "行為後法律有所變動時，行政罰法採取從新從輕原則", "基於公平及平等原則，行政罰法未規定阻卻違法事由", "違反行政法義務之處罰，得因時因地制宜由主管機關任意制定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00086', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '汽車駕駛人違規行駛，受記點處分，該法律性質為何？', '["剝奪資格之處分", "警告性處分", "下命處分", "影響名譽之處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00087', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列何者非屬行政執行方法中之直接強制？', '["解除占有", "註銷證照", "代履行", "斷絕營業所必須之電力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00088', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於行政執行不利處置之敘述，下列何者錯誤？', '["怠金為間接強制方法", "不利處置非僅怠金一種", "怠金得連續裁處", "不服怠金裁處者得提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00089', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於行政執行之限制住居，下列敘述何者正確？', '["義務人滯欠金額合計未達新臺幣20萬元，不得限制住居。但義務人已出境達2次者，不在此限", "義務人經合法通知，無正當理由而不到場，得限制其住居", "執行機關得不命義務人提供相當擔保，限期履行，而僅限制其住居", "義務人已按法定應繼分繳納遺產稅款、罰鍰及加徵之滯納金、利息，仍得限制住居"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00090', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '行政程序法關於行政機關調查事實及證據之規定，下列敘述何者錯誤？', '["行政機關實施勘驗時，應通知當事人到場。但不能通知者，不在此限", "當事人僅得向行政機關申請調查事實及證據，不得自行提出證據", "行政機關得要求當事人或第三人提供必要之文書、資料或物品", "行政機關得選定適當之人以書面為鑑定，必要時，得通知鑑定人到場說明"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00091', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-113-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '關於政府資訊公開之敘述，下列何者錯誤？', '["政府資訊中若有含限制公開事項，因情事變更已無限制公開必要者，政府機關應受理申請提供", "政府機關就人民申請提供、更正或補充政府資訊所為之決定，其性質為行政處分", "政府資訊公開有侵害個人隱私者，為維護公益即得公開", "政府資訊之公開若足以妨害刑事被告受公正之裁判時，行政機關應限制公開"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:42+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "420", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL)
